function validAiAgentReview(overrides: Partial<DecisionAiAgentReview> = {}): DecisionAiAgentReview {
  return {
    reviewVerdict: "agree",
    recommendedAction: "consider",
    confidenceAdjustment: "keep",
    riskAdjustment: "keep",
    summary: "AI reviewer agrees after checking cited evidence and safety gates.",
    rationale: ["The value edge is supported by the supplied market evidence."],
    riskFlags: ["Market price can move before kickoff."],
    dataGaps: ["Weather check"],
    saferAlternatives: ["Double chance remains a lower-variance alternative."],
    checksBeforeAction: ["Refresh bookmaker odds."],
    auditSummary: "The AI cited supplied evidence and found no blocking safety gate.",
    evidenceChecks: [
      {
        id: "ai-market-check",
        label: "Market edge check",
        status: "supports",
        citedEvidenceIds: ["evidence-2-market"],
        finding: "The supplied no-vig market comparison supports the edge.",
        requiredFollowUp: "Refresh odds before action."
      }
    ],
    safetyGates: [
      {
        id: "ai-no-upgrade",
        label: "No upgrade guardrail",
        status: "pass",
        reason: "The AI does not promote a weaker local action."
      }
    ],
    unsupportedClaims: [],
    ...overrides
  };
}

function withStoredLiveReadback<T extends { payload: { rows: any[] }; readback: any; controls: any }>(receipt: T): T {
  const rows = receipt.payload.rows.map((row, index) => {
    const features = row.features ?? {};
    const targets = row.targets ?? {};
    const homeName = features.homeTeam?.name ?? "Home";
    const awayName = features.awayTeam?.name ?? "Away";
    return {
      id: `stored-live-row-${index + 1}`,
      fixtureExternalId: row.fixture_external_id,
      modelKey: row.model_key,
      split: "live" as const,
      source: row.source,
      label: row.label ?? null,
      featureHash: row.feature_hash ?? null,
      settlementStatus: targets.settlementStatus ?? "pending",
      rawPayloadLinked: features.evidence?.rawPayloadLinked === true,
      fixtureProvider: features.dataSource?.fixtureProvider ?? null,
      oddsProvider: features.dataSource?.oddsProvider ?? null,
      matchLabel: `${homeName} vs ${awayName}`,
      league: features.league?.name ?? null,
      generatedAt: row.generated_at ?? null,
      createdAt: row.created_at ?? null
    };
  });

  return {
    ...receipt,
    readback: {
      checked: true,
      evidenceReady: rows.length > 0,
      matchedRows: rows.length,
      rows,
      error: null
    },
    controls: {
      ...receipt.controls,
      canUseStoredMonitorEvidence: rows.length > 0
    }
  } as T;
}

