  it("builds weighted factors that explain the decision score", async () => {
    const [match] = await mockSportsDataProvider.getFixtures("2026-06-24", "football");
    const prediction = buildPrediction(match);
    const weightedTotal = prediction.decision.factors.reduce((sum, factor) => sum + factor.weightedScore, 0);

    expect(prediction.decision.factors.map((factor) => factor.key)).toEqual(
      expect.arrayContaining(["value_edge", "expected_value", "confidence", "data_quality", "variance", "missing_context", "case_memory"])
    );
    expect(prediction.decision.decisionScore).toBe(weightedTotal);
    for (const factor of prediction.decision.factors) {
      expect(factor.score).toBeGreaterThanOrEqual(-100);
      expect(factor.score).toBeLessThanOrEqual(100);
    }
  });

