    expect(slateThinking.nextThought?.safeCommand).toContain("http://127.0.0.1:3025/api/sports/decision/");
    expect(slateThinking.nextThought?.safeCommand).not.toContain("http://127.0.0.1:3013");
    expect(slateThinking.nextThought?.nextEvidenceAction.length).toBeGreaterThan(20);
    expect(slateThinking.nextThought?.riskSummary.length).toBeGreaterThan(20);
    expect(slateThinking.nextThought?.saferAlternatives.length).toBeGreaterThan(0);
    expect(slateThinking.thoughts.every((thought) => thought.riskSummary.length > 20)).toBe(true);
