  it("builds paper-only portfolio risk from the cross-sport odds board", async () => {
    const slates = await Promise.all(
      DECISION_MULTI_SPORTS.map(async (sport) => ({
        sport,
        rows: (await mockSportsDataProvider.getFixtures("2026-06-24", sport)).slice(0, 4).map((match) => ({
          match,
          prediction: buildPrediction(match)
        }))
      }))
    );
    const board = buildDecisionOddsBoard({ date: "2026-06-24", slates, limit: 40 });
    const portfolio = buildDecisionPortfolioRisk({ board, limit: 8 });

    expect(["paper-ready", "needs-review", "blocked"]).toContain(portfolio.status);
    expect(portfolio.portfolioHash).toMatch(/^fnv1a-[a-f0-9]{8}$/);
    expect(portfolio.budget.paperBankrollUnits).toBe(100);
    expect(portfolio.budget.fractionalKelly).toBeGreaterThan(0);
    expect(portfolio.budget.suggestedPaperUnits).toBeGreaterThanOrEqual(0);
    expect(portfolio.budget.suggestedPaperUnits).toBeLessThanOrEqual(portfolio.budget.paperBankrollUnits);
    expect(portfolio.sizingAudit.finalPaperUnits).toBe(portfolio.budget.suggestedPaperUnits);
    expect(portfolio.sizingAudit.includedRawUnits).toBeGreaterThanOrEqual(portfolio.sizingAudit.finalPaperUnits);
    expect(portfolio.sizingAudit.totalCapHaircutUnits).toBeGreaterThanOrEqual(0);
    expect(portfolio.sizingAudit.averageCapHaircut).toBeGreaterThanOrEqual(0);
    expect(portfolio.sizingAudit.explanation).toContain("raw Kelly");
    expect(portfolio.totals.candidates).toBeGreaterThan(0);
    expect(portfolio.totals.included + portfolio.totals.capped + portfolio.totals.watchOnly + portfolio.totals.excluded).toBeGreaterThan(0);
    expect(portfolio.stressTests.map((scenario) => scenario.id)).toEqual(
      portfolio.portfolio.length
        ? ["probability-haircut", "odds-shortening", "correlated-loss", "data-quality-shock"]
        : ["probability-haircut"]
    );
    expect(portfolio.stressTests.every((scenario) => ["survives", "review", "fails", "empty"].includes(scenario.status))).toBe(true);
    expect(portfolio.stressTests.every((scenario) => scenario.drawdownUnits >= 0)).toBe(true);
    expect(portfolio.policy.canStake).toBe(false);
    expect(portfolio.policy.canPromote).toBe(false);
    expect(portfolio.policy.canPersist).toBe(false);
    expect(portfolio.policy.canPublish).toBe(false);
    expect(portfolio.policy.canTrain).toBe(false);
    if (portfolio.portfolio.length) {
      expect(portfolio.portfolio[0].suggestedPaperUnits).toBeLessThanOrEqual(portfolio.budget.maxCandidateUnits);
      expect(portfolio.portfolio[0].rawKellyFraction).toBeGreaterThanOrEqual(portfolio.portfolio[0].paperKellyFraction);
      expect(portfolio.portfolio[0].paperKellyFraction).toBeGreaterThanOrEqual(portfolio.portfolio[0].adjustedKellyFraction);
      expect(portfolio.portfolio[0].sizingAudit.rawUnits).toBeGreaterThanOrEqual(portfolio.portfolio[0].sizingAudit.finalUnits);
      expect(portfolio.portfolio[0].sizingAudit.verdict).toMatch(/included|capped/);
      expect(portfolio.portfolio[0].sizingAudit.explanation).toMatch(/Kelly|caps|risk controls/i);
      expect(portfolio.portfolio[0].riskControls.length).toBeGreaterThan(0);
      expect(portfolio.portfolio[0].verifyUrl).toContain("/api/sports/decision/");
    }
  });

