  it("applies an active learned minimum edge as a hard abstention gate", async () => {
    const matches = await mockSportsDataProvider.getFixtures("2026-06-24", "football");
    const match =
      matches.find((candidate) => {
        const base = buildPrediction(candidate);
        const internalCandidate = decisionCandidatePick(base);
        return internalCandidate.hasValue && internalCandidate.edge < 0.09;
      }) ?? matches[0];
    const learningProfile: DecisionLearningProfile = {
      status: "active",
      source: "supabase:op_fixtures:real-only",
      active: true,
      sampleSize: 1200,
      realFinishedFixtures: 1200,
      minimumRecommendedFixtures: 1000,
      minimumEdge: 0.09,
      valueEdgeWeight: 0.44,
      dataQualityWeight: 0.22,
      marketAdjustmentWeight: 0.12,
      homeAdvantageElo: 62,
      brierScore: 0.19,
      yield: 0.04,
      closingLineValue: 0.02,
      generatedAt: "2026-06-24T10:00:00.000Z",
      reason: "Real-data backtest is active.",
      notes: []
    };
    const prediction = buildPrediction(match, { learningProfile });
    const learnedGate = prediction.decision.abstentionRules.find((rule) => rule.id === "learned-minimum-edge");

    expect(prediction.decision.learningProfile?.active).toBe(true);
    expect(prediction.bestPick.hasValue).toBe(false);
    expect(learnedGate?.triggered).toBe(true);
    expect(prediction.decision.action).toBe("avoid");
    expect(prediction.decision.recommendedSelection).toBeNull();
    expect(prediction.decision.publicReasoningSteps.join(" ")).toContain("Historical learning profile: active");
  });

