  it("builds a cross-match supervisor queue from control policies and tool blockers", async () => {
    const matches = await mockSportsDataProvider.getFixtures("2026-06-24", "football");
    const rows = matches.slice(0, 4).map((match) => ({
      match,
      prediction: buildPrediction(match)
    }));
    const queue = buildDecisionSupervisorQueue({ rows, date: "2026-06-24", sport: "football", limit: 8, env: {} });

    expect(["clear", "active", "blocked"]).toContain(queue.status);
    expect(queue.totalMatches).toBe(rows.length);
    expect(queue.items.length).toBeGreaterThan(0);
    expect(queue.nextItem).toEqual(queue.items[0]);
    expect(queue.items.map((item) => item.type)).toEqual(expect.arrayContaining(["control-gate", "tool-task"]));
    expect(queue.items.every((item) => item.matchId.length > 0 && item.action.length > 0)).toBe(true);
    expect(["ready", "waiting", "blocked"]).toContain(queue.runbook.status);
    expect(["read-only", "dry-run", "write-gated"]).toContain(queue.runbook.mode);
    expect(queue.runbook.steps.length).toBeGreaterThan(0);
    expect(queue.runbook.steps.some((step) => step.id === "verify-supervisor-queue")).toBe(true);
    expect(queue.runbook.primaryCommand).toContain("curl.exe");
    expect(queue.runbook.primaryCommand).toContain("127.0.0.1:3025");
    expect(queue.runbook.primaryCommand).not.toContain("127.0.0.1:3013");
    expect(queue.runbook.preflight.status).toBe("blocked");
    expect(queue.runbook.preflight.canRunPrimaryCommand).toBe(false);
    expect(queue.runbook.preflight.missingEnv).toContain("ODDSPADI_ADMIN_TOKEN");
    expect(queue.runbook.preflight.checks.some((check) => check.id === "required-env" && check.status === "fail")).toBe(true);
    expect(queue.runbook.preflight.checks.some((check) => check.id === "write-safety")).toBe(true);
    expect(queue.summary).toContain("Supervisor queue");
  });

