  it("validates prediction outcome input for the learning loop", () => {
    const parsed = parsePredictionOutcomeInput({
      fixtureExternalId: "epl-001",
      sport: "football",
      market: "Both Teams To Score",
      selection: "BTTS Yes",
      modelProbability: 0.61,
      impliedProbability: 0.53,
      valueEdge: 0.08,
      odds: 1.9,
      closingOdds: 1.82,
      result: "won",
      source: "manual"
    });

    expect("error" in parsed).toBe(false);
    if (!("error" in parsed)) {
      expect(parsed.fixtureExternalId).toBe("epl-001");
      expect(parsed.result).toBe("won");
      expect(parsed.metadata).toEqual({});
    }

    expect(parsePredictionOutcomeInput({ fixtureExternalId: "epl-001", sport: "football", result: "won" })).toEqual({
      error: "market is required."
    });
    expect(
      parsePredictionOutcomeInput({
        fixtureExternalId: "epl-001",
        sport: "football",
        market: "Both Teams To Score",
        selection: "BTTS Yes",
        result: "guaranteed"
      })
    ).toEqual({ error: "result is invalid." });
  });

  it("previews deterministic outcome settlement rows for calibration without writing", () => {
    const homeWin = buildDecisionOutcomeSettlement(
      {
        fixtureExternalId: "epl-001",
        sport: "football",
        market: "match_winner",
        selection: "home",
        homeScore: 2,
        awayScore: 1,
        modelProbability: 0.58,
        impliedProbability: 0.52,
        valueEdge: 0.06,
        odds: 1.88,
        closingOdds: 1.74,
        source: "test"
      },
      new Date("2026-07-02T00:00:00.000Z")
    );
    const totalPush = buildDecisionOutcomeSettlement(
      {
        fixtureExternalId: "nba-001",
        sport: "basketball",
        market: "total_points",
        selection: "over",
        homeScore: 110,
        awayScore: 109,
        line: 219,
        odds: 1.9
      },
      new Date("2026-07-02T00:00:00.000Z")
    );
    const homeSpreadLoss = buildDecisionOutcomeSettlement(
      {
        fixtureExternalId: "nba-002",
        sport: "basketball",
        market: "spread",
        selection: "home_cover",
        homeScore: 102,
        awayScore: 99,
        line: -5.5,
        odds: 1.91
      },
      new Date("2026-07-02T00:00:00.000Z")
    );

    expect(homeWin.mode).toBe("decision-outcome-settlement");
    expect(homeWin.status).toBe("graded");
    expect(homeWin.result).toBe("won");
    expect(homeWin.settlement.roiUnits).toBe(0.88);
    expect(homeWin.settlement.brierScore).toBeCloseTo(0.1764);
    expect(homeWin.settlement.closingLineValue).toBeCloseTo(0.08046);
    expect(homeWin.outcomeInput).toEqual(
      expect.objectContaining({
        fixtureExternalId: "epl-001",
        sport: "football",
        market: "match_winner",
        selection: "home",
        result: "won",
        settledAt: "2026-07-02T00:00:00.000Z"
      })
    );
    expect(homeWin.outcomeInput?.metadata).toEqual(
      expect.objectContaining({
        homeScore: 2,
        awayScore: 1,
        settlementMode: "deterministic-score-grader"
      })
    );
    expect(homeWin.controls.canPersist).toBe(false);
    expect(homeWin.controls.canTrainModels).toBe(false);
    expect(homeWin.controls.canPublishPicks).toBe(false);
    expect(homeWin.controls.canStake).toBe(false);
    expect(totalPush.result).toBe("push");
    expect(totalPush.settlement.roiUnits).toBe(0);
    expect(homeSpreadLoss.result).toBe("lost");
    expect(homeSpreadLoss.settlement.roiUnits).toBe(-1);
  });

