  it("builds an API-Football provider readiness probe that blocks safely when the key is missing", async () => {
    const probe = await buildApiFootballProviderReadinessProbe({
      generatedAt: "2026-07-02T00:00:00.000Z",
      baseUrl: "http://127.0.0.1:3025",
      env: {},
      syncImpl: async ({ request }) => ({
        status: "not-configured",
        configured: false,
        provider: "api-football",
        dryRun: request.dryRun ?? true,
        endpoint: "https://v3.football.api-sports.io/fixtures?league=39&season=2025&timezone=UTC",
        fetched: 0,
        normalized: 0,
        reason: "Missing API_FOOTBALL_KEY, APISPORTS_KEY, or SPORTS_API_KEY."
      })
    });

    expect(probe.status).toBe("blocked");
    expect(probe.configured).toBe(false);
    expect(probe.canRunFirstBackfillDryRun).toBe(false);
    expect(probe.checks.find((check) => check.id === "fixtures")?.status).toBe("block");
    expect(probe.blockers[0]).toContain("API_FOOTBALL_KEY");
    expect(probe.firstBackfillDryRunCommand).toContain("/api/sports/decision/training/backfill?");
    expect(probe.firstBackfillDryRunCommand).toContain("dryRun=1");
  });

