  it("builds a The Odds API readiness probe that blocks safely when the key is missing", async () => {
    const probe = await buildTheOddsApiProviderReadinessProbe({
      generatedAt: "2026-07-02T00:00:00.000Z",
      baseUrl: "http://127.0.0.1:3025",
      env: {},
      request: { sportKey: "soccer_epl", date: "2026-08-21T12:00:00Z", regions: "uk", limit: 3 },
      syncImpl: async ({ request }) => ({
        status: "not-configured",
        configured: false,
        provider: "the-odds-api",
        dryRun: request.dryRun ?? true,
        endpoint: "https://api.the-odds-api.com/v4/historical/sports/soccer_epl/odds/?markets=h2h",
        fetched: 0,
        normalized: 0,
        reason: "Missing THE_ODDS_API_KEY or ODDS_API_KEY."
      })
    });

    expect(probe.status).toBe("blocked");
    expect(probe.configured).toBe(false);
    expect(probe.canRunFirstOddsDryRun).toBe(false);
    expect(probe.checks.find((check) => check.id === "credential")?.status).toBe("block");
    expect(probe.blockers.join(" ")).toContain("THE_ODDS_API_KEY");
    expect(probe.firstOddsDryRunCommand).toContain("/api/sports/decision/training/provider-sync?");
    expect(probe.firstOddsDryRunCommand).toContain("provider=the-odds-api");
    expect(probe.firstOddsDryRunCommand).toContain("dryRun=1");
  });

