    expect(tennis?.adapterStatus).toBe("implemented");
    expect(tennis?.backtestRunnerStatus).toBe("implemented");
    expect(tennis?.backtestModelKey).toBe("tennis-surface-elo-match-winner-v1");
    expect(tennis?.firstDryRunCommand?.command).toContain("provider=api-tennis");
    expect(tennis?.blockers).toHaveLength(0);
