  it("parses and applies a guarded AI decision-agent downgrade", async () => {
    const [match] = await mockSportsDataProvider.getFixtures("2026-06-24", "football");
    const prediction = buildPrediction(match);
    const decision = {
      ...prediction.decision,
      verdict: "lean-value" as const,
      action: "consider" as const,
      confidence: "high" as const,
      risk: "low" as const,
      recommendedSelection: "Home win"
    };
    const review = safeParseAiAgentReview(
      JSON.stringify(
        validAiAgentReview({
        reviewVerdict: "abstain",
        recommendedAction: "avoid",
        confidenceAdjustment: "lower",
        riskAdjustment: "raise",
        summary: "AI reviewer would abstain because lineups and injury data are missing.",
        rationale: ["Missing context is material."],
        riskFlags: ["Lineups are not confirmed."],
        dataGaps: ["Injury report"],
        saferAlternatives: ["Double chance only after fresh odds."],
        checksBeforeAction: ["Refresh odds.", "Check team news."],
        auditSummary: "The AI found one material context gap and a blocking safety gate.",
        evidenceChecks: [
          {
            id: "ai-context-check",
            label: "Context availability check",
            status: "missing",
            citedEvidenceIds: ["evidence-5-weather"],
            finding: "The supplied weather/context evidence is missing and should block a public pick.",
            requiredFollowUp: "Check team news and weather."
          }
        ],
        safetyGates: [
          {
            id: "ai-context-block",
            label: "Material context gap",
            status: "block",
            reason: "The review says lineups and injuries are needed before action."
          }
        ]
      })
      )
    );

    expect(review).not.toBeNull();
    if (!review) return;

    const adjusted = applyAiAgentReviewToDecision({ decision, review, model: "gpt-5.5" });
    expect(adjusted.action).toBe("avoid");
    expect(adjusted.verdict).toBe("avoid");
    expect(adjusted.recommendedSelection).toBeNull();
    expect(adjusted.confidence).toBe("medium");
    expect(adjusted.risk).toBe("medium");
    expect(adjusted.aiAgentReviewed).toBe(true);
    expect(adjusted.aiProtocol.mode).toBe("openai-reviewed");
    expect(adjusted.aiProtocol.status).toBe("reviewed");
    expect(adjusted.aiProtocol.checks.some((check) => check.id === "openai-review")).toBe(true);
    expect(adjusted.toolOrchestration.tasks.find((task) => task.id === "openai-review")?.status).toBe("complete");
    expect(adjusted.toolExecution.mode).toBe("openai-reviewed");
    expect(adjusted.toolExecution.attempts.find((attempt) => attempt.taskId === "openai-review")?.status).toBe("executed");
    expect(adjusted.controlPolicy.aiReviewRequired).toBe(false);
    expect(adjusted.controlPolicy.gates.find((gate) => gate.id === "ai-review")?.status).toBe("block");
    expect(adjusted.aiAgentAudit?.safetyGates[0].status).toBe("block");
    expect(adjusted.aiAgentAudit?.evidenceChecks[0].citedEvidenceIds).toEqual(["evidence-5-weather"]);
    expect(adjusted.publicReasoningSteps.join(" ")).toContain("local guardrails prevent upward promotion");
    expect(adjusted.publicReasoningSteps.join(" ")).toContain("AI evidence audit cited");
    const payload = buildDecisionRunPayload({ match, prediction, decision: adjusted });
    expect((payload.model_snapshot as { aiAgentAudit?: unknown }).aiAgentAudit).toEqual(adjusted.aiAgentAudit);
  });

